/**
 * Layout component that queries for data
 * with Gatsby's useStaticQuery component
 *
 * See: https://www.gatsbyjs.org/docs/use-static-query/
 */

import React, { useEffect, useState } from "react"
import { Link } from "gatsby"
import { globalHistory } from "@reach/router"
//import "./layout.css"
// import './core-ui/css/fontawesome-free/css/all.min.css'
// import 'bootstrap/dist/css/bootstrap.min.css'
// import "./core-ui/css/clean-blog.min.css"
import { Navbar, Nav, NavItem } from "reactstrap"
import PropTypes from "prop-types"
import { useStaticQuery, graphql } from "gatsby"

import Header from "./header"

const Layout = ({ children, postInfo }) => {
  //console.log(postInfo)
  if (postInfo) {
    var { postTitle, postDate } = postInfo
  }
  const data = useStaticQuery(graphql`
    query SiteTitleQuery {
      site {
        siteMetadata {
          title
        }
      }
    }
  `)
  // State of our Menu
  const [state, setState] = useState({
    clicked: false,
  })

  // Toggle menu
  const handleMenu = () => {
    if (state.clicked === true) {
      console.log("clicked true");
      setState({
        clicked: !state.clicked,
      })
    } else if (state.clicked === false) {
      console.log("clicked false");
      setState({
        clicked: !state.clicked,
      })
    }
  }

  useEffect(() => {
    // //Listening for page changes.
    // globalHistory.listen(() => {
    //   setState({ clicked: false })
    //   console.log("Route change")
    // })
    var body = document.querySelector("body")
    // body.classList.add("nav-active")
    // If the menu is open and we click the menu button to close it.
    if (state.clicked === false) {
      // If menu is closed and we want to open it.
      body.classList.remove("nav-active")
    } else if (
      state.clicked === true
    ) {
      body.classList.add("nav-active")
    }
  })
  return (
    <>
      <div class="nav">
        <div class="nav__content">
          <div class="container">
            <ul class="nav__list p-4 p-lg-0">
              <div className="overflow-hidden">
                <li class="nav__list-item" activeClassName="active-nav">
                  <Link className="hover-target" to="/">
                    Home
                  </Link>
                </li>
              </div>
              <div className="overflow-hidden">
                <li class="nav__list-item" activeClassName="active-nav">
                  <Link className="hover-target" to="/blog">
                    Blog
                  </Link>
                </li>
              </div>
              {/* <li class="nav__list-item"><a href="#" class="hover-target">About</a></li> */}
              <div className="overflow-hidden">
                <li class="nav__list-item" activeClassName="active-nav">
                  <Link className="hover-target" to="/search">
                    Search
                  </Link>
                </li>
              </div>
            </ul>
          </div>
        </div>
      </div>

      <Navbar
        className="navbar navbar-expand-lg navbar-light p-5 fixed-top"
        id="mainNav"
      >
        <Nav className="ml-auto" navbar>
          <NavItem onClick={handleMenu}>
            <div class="nav-link menu-icon hover-target">
              <span class="menu-icon__line menu-icon__line-left"></span>
              <span class="menu-icon__line"></span>
              <span class="menu-icon__line menu-icon__line-right"></span>
            </div>
          </NavItem>
        </Nav>
      </Navbar>

      {postTitle && postDate ? (
        <Header postInfo={{ postTitle, postDate }} />
      ) : (
        <Header siteTitle={data.site.siteMetadata.title} />
      )}
      <main className="container">{children}</main>
      <footer className="justify-content-center">
        © {new Date().getFullYear()}, Built with
        {` `}
        <a href="https://www.gatsbyjs.org">Gatsby</a>
      </footer>
    </>
  )
}

Layout.propTypes = {
  children: PropTypes.node.isRequired,
}

export default Layout
